				call, ok := n.(*ast.CallExpr)
				if !ok {
					return true
				}
				sel, ok := call.Fun.(*ast.SelectorExpr)
				if !ok {
					return true
				}
				ident, ok := sel.X.(*ast.Ident)
				if !ok {
					return true
				}
				if ident.Name == "time" && sel.Sel.Name == "Sleep" {
					pass.Reportf(call.Pos(), "time.Sleep() はテストを不安定にします。チャネルやsync.WaitGroupの使用を検討してください")
				}
				return true
			})
		}
	}
	return nil, nil
