45→			return nil // パースエラーは無視して続行
46→		}
47→		allSmells = append(allSmells, smells...)
48→		return nil
49→	})
50→	return allSmells, err
51→}
52→
53→// ScanFile は単一のテストファイルをスキャンする。
54→func (s *Scanner) ScanFile(path string) ([]TestSmell, error) {
55→	fset := token.NewFileSet()
56→	file, err := parser.ParseFile(fset, path, nil, parser.ParseComments)
57→	if err != nil {
58→		return nil, err
59→	}
60→	return s.scanAST(fset, file), nil
61→}
62→
63→// ScanSource はソースコード文字列をスキャンする（テスト用）。
64→func (s *Scanner) ScanSource(src string) ([]TestSmell, error) {
65→	fset := token.NewFileSet()
66→	file, err := parser.ParseFile(fset, "test_test.go", src, parser.ParseComments)
67→	if err != nil {
68→		return nil, err
69→	}
70→	return s.scanAST(fset, file), nil
71→}
72→
73→func (s *Scanner) scanAST(fset *token.FileSet, file *ast.File) []TestSmell {
74→	var smells []TestSmell
75→	for _, decl := range file.Decls {
76→		fn, ok := decl.(*ast.FuncDecl)
77→		if !ok {
78→			continue
79→		}
80→		for _, detector := range s.Detectors {
81→			if !s.isEnabled(detector.Type()) {
82→				continue
83→			}
84→			smells = append(smells, detector.Detect(fset, file, fn)...)
85→		}
86→	}
87→	return smells
88→}
89→
90→func (s *Scanner) isEnabled(t SmellType) bool {
91→	if len(s.EnabledSmells) > 0 {
92→		return s.EnabledSmells[t]
93→	}
94→	if len(s.DisabledSmells) > 0 {
95→		return !s.DisabledSmells[t]
96→	}
97→	return true
98→}
