15→	Run:  runMagicNumberTest,
16→}
17→
18→func runMagicNumberTest(pass *analysis.Pass) (any, error) {
19→	for _, file := range pass.Files {
20→		filename := pass.Fset.Position(file.Pos()).Filename
21→		if !strings.HasSuffix(filename, "_test.go") {
22→			continue
23→		}
24→		for _, decl := range file.Decls {
25→			fn, ok := decl.(*ast.FuncDecl)
26→			if !ok {
27→				continue
28→			}
29→			if !isTestFunc(fn) {
30→				continue
31→			}
32→			if fn.Body == nil {
33→				continue
34→			}
35→			ast.Inspect(fn.Body, func(n ast.Node) bool {
36→				call, ok := n.(*ast.CallExpr)
37→				if !ok {
38→					return true
39→				}
40→				if !isAssertionCall(call) {
41→					return true
42→				}
43→				for _, arg := range call.Args {
44→					if lit, ok := arg.(*ast.BasicLit); ok {
45→						if lit.Kind == token.INT || lit.Kind == token.FLOAT {
46→							if !allowedNumbers[lit.Value] {
47→								pass.Reportf(lit.Pos(), "マジックナンバー %s には名前付き定数を使用してください", lit.Value)
48→							}
49→						}
50→					}
51→					if unary, ok := arg.(*ast.UnaryExpr); ok && unary.Op == token.SUB {
52→						if lit, ok := unary.X.(*ast.BasicLit); ok {
53→							if lit.Kind == token.INT || lit.Kind == token.FLOAT {
54→								val := "-" + lit.Value
55→								if !allowedNumbers[val] {
56→									if _, err := strconv.ParseFloat(lit.Value, 64); err == nil {
57→										pass.Reportf(unary.Pos(), "マジックナンバー %s には名前付き定数を使用してください", val)
58→									}
59→								}
60→							}
61→						}
62→					}
63→				}
64→				return true
65→			})
66→		}
67→	}
68→	return nil, nil
69→}
