33→// assertionMethods は t.Error, t.Fatal 等のアサーション系メソッド名。
34→var assertionMethods = map[string]bool{
35→	"Error":  true,
36→	"Errorf": true,
37→	"Fatal":  true,
38→	"Fatalf": true,
39→	"Fail":   true,
40→	"FailNow": true,
41→}
