43→// testifyMethods は testify の assert/require 関数名。
44→var testifyMethods = map[string]bool{
45→	"Equal":         true,
46→	"NotEqual":      true,
47→	"True":          true,
48→	"False":         true,
49→	"Nil":           true,
50→	"NotNil":        true,
51→	"NoError":       true,
52→	"Error":         true,
53→	"Contains":      true,
54→	"NotContains":   true,
55→	"Len":           true,
56→	"Empty":         true,
57→	"NotEmpty":      true,
58→	"Zero":          true,
59→	"NotZero":       true,
60→	"Greater":       true,
61→	"Less":          true,
62→	"Panics":        true,
63→	"JSONEq":        true,
64→	"ElementsMatch": true,
65→}
