67→func hasAssertion(body *ast.BlockStmt) bool {
68→	found := false
69→	ast.Inspect(body, func(n ast.Node) bool {
70→		if found {
71→			return false
72→		}
73→		call, ok := n.(*ast.CallExpr)
74→		if !ok {
75→			return true
76→		}
77→		// t.Error(), t.Fatal() 等
78→		sel, ok := call.Fun.(*ast.SelectorExpr)
79→		if ok {
80→			if assertionMethods[sel.Sel.Name] {
81→				found = true
82→				return false
83→			}
84→			// testify: assert.Equal(), require.NoError() 等
85→			if ident, ok := sel.X.(*ast.Ident); ok {
86→				if (ident.Name == "assert" || ident.Name == "require") && testifyMethods[sel.Sel.Name] {
87→					found = true
88→					return false
89→				}
90→			}
91→		}
92→		return true
93→	})
94→	return found
95→}
