  9→// MagicNumberTestDetector はアサーション内のマジックナンバーを検出する。
 10→type MagicNumberTestDetector struct{}
 11→
 12→func (d *MagicNumberTestDetector) Type() SmellType { return SmellMagicNumberTest }
 13→
 14→// 許容される数値リテラル
 15→var allowedNumbers = map[string]bool{
 16→	"0":    true,
 17→	"1":    true,
 18→	"2":    true,
 19→	"-1":   true,
 20→	"0.0":  true,
 21→	"1.0":  true,
 22→	"true": true,
 23→	"false": true,
 24→}
 25→
 26→func (d *MagicNumberTestDetector) Detect(fset *token.FileSet, file *ast.File, fn *ast.FuncDecl) []TestSmell {
 27→	if !isTestFunc(fn) {
 28→		return nil
 29→	}
 30→	if fn.Body == nil {
 31→		return nil
 32→	}
 33→
 34→	var smells []TestSmell
 35→	ast.Inspect(fn.Body, func(n ast.Node) bool {
 36→		call, ok := n.(*ast.CallExpr)
 37→		if !ok {
 38→			return true
 39→		}
 40→		if !isAssertionCall(call) {
 41→			return true
 42→		}
 43→		for _, arg := range call.Args {
 44→			if lit, ok := arg.(*ast.BasicLit); ok {
 45→				if lit.Kind == token.INT || lit.Kind == token.FLOAT {
 46→					if !allowedNumbers[lit.Value] {
 47→						pos := fset.Position(lit.Pos())
 48→						smells = append(smells, TestSmell{
 49→							Type:     SmellMagicNumberTest,
 50→							File:     pos.Filename,
 51→							FuncName: fn.Name.Name,
 52→							Line:     pos.Line,
 53→							Message:  "マジックナンバー " + lit.Value + " には名前付き定数を使用してください",
 54→						})
 55→					}
 56→				}
 57→			}
 58→			// 負の数値: -42 のようなケース
 59→			if unary, ok := arg.(*ast.UnaryExpr); ok && unary.Op == token.SUB {
 60→				if lit, ok := unary.X.(*ast.BasicLit); ok {
 61→					if lit.Kind == token.INT || lit.Kind == token.FLOAT {
 62→						val := "-" + lit.Value
 63→						if !allowedNumbers[val] {
 64→							if _, err := strconv.ParseFloat(lit.Value, 64); err == nil {
 65→								pos := fset.Position(unary.Pos())
 66→								smells = append(smells, TestSmell{
 67→									Type:     SmellMagicNumberTest,
 68→									File:     pos.Filename,
 69→									FuncName: fn.Name.Name,
 70→									Line:     pos.Line,
 71→									Message:  "マジックナンバー " + val + " には名前付き定数を使用してください",
 72→								})
 73→							}
 74→						}
 75→					}
 76→				}
 77→			}
 78→		}
 79→		return true
 80→	})
 81→	return smells
 82→}
 83→
 84→func isAssertionCall(call *ast.CallExpr) bool {
 85→	sel, ok := call.Fun.(*ast.SelectorExpr)
 86→	if !ok {
 87→		return false
 88→	}
 89→	// t.Error, t.Fatal 等
 90→	if assertionMethods[sel.Sel.Name] {
 91→		return true
 92→	}
 93→	// assert.Equal, require.Equal 等
 94→	if ident, ok := sel.X.(*ast.Ident); ok {
 95→		if (ident.Name == "assert" || ident.Name == "require") && testifyMethods[sel.Sel.Name] {
 96→			return true
 97→		}
 98→	}
 99→	return false
100→}
