 8→// MissingErrorCheckDetector は error 戻り値を _ で無視しているケースを検出する。
 9→type MissingErrorCheckDetector struct{}
10→
11→func (d *MissingErrorCheckDetector) Type() SmellType { return SmellMissingErrorCheck }
12→
13→func (d *MissingErrorCheckDetector) Detect(fset *token.FileSet, file *ast.File, fn *ast.FuncDecl) []TestSmell {
14→	if !isTestFunc(fn) {
15→		return nil
16→	}
17→	if fn.Body == nil {
18→		return nil
19→	}
20→
21→	var smells []TestSmell
22→	ast.Inspect(fn.Body, func(n ast.Node) bool {
23→		assign, ok := n.(*ast.AssignStmt)
24→		if !ok {
25→			return true
26→		}
27→		// 最後の戻り値が _ で、変数名が err パターンのものを検出
28→		if len(assign.Lhs) < 2 {
29→			return true
30→		}
31→		last := assign.Lhs[len(assign.Lhs)-1]
32→		ident, ok := last.(*ast.Ident)
33→		if !ok {
34→			return true
35→		}
36→		if ident.Name == "_" {
37→			// 関数呼び出しの戻り値で最後が _ の場合、error を無視している可能性
38→			if _, ok := assign.Rhs[0].(*ast.CallExpr); ok {
39→				pos := fset.Position(assign.Pos())
40→				smells = append(smells, TestSmell{
41→					Type:     SmellMissingErrorCheck,
42→					File:     pos.Filename,
43→					FuncName: fn.Name.Name,
44→					Line:     pos.Line,
45→					Message:  "error の戻り値が無視されています。テストでもエラーチェックを行ってください",
46→				})
47→			}
48→		}
49→		return true
50→	})
51→	return smells
52→}
